# ─────────────────────────────────────────────
# PARSER
# ─────────────────────────────────────────────

def parse_config(content: str) -> dict:
    config = {
        "filters": {}, "routing_rules": {}, "replacing_rules": {},
        "can_interfaces": {}, "ethernet": {}, "fuse_notifications": {},
    }

    # FILTROS
    sec = re.search(r'!FILTERS(.*?)(?=!ROUTINGRULES|$)', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        for iface in range(6):
            rows = []
            for idx in range(10):
                idb = re.search(rf'#IF{iface};FlIDB{idx};(0x[0-9A-Fa-f]+)', text)
                msk = re.search(rf'#IF{iface};FlMSK{idx};(0x[0-9A-Fa-f]+)', text)
                flg = re.search(rf'#IF{iface};FlFLG{idx};(0x[0-9A-Fa-f]+)', text)
                if idb and msk and flg:
                    iv, mv, fv = idb.group(1), msk.group(1), flg.group(1)
                    enabled = not (iv == '0x0' and mv == '0x0' and fv == '0x0')
                    rows.append({"index": idx, "idb": iv, "msk": mv, "flg": fv, "enabled": enabled})
            config["filters"][iface] = rows

    # ROUTING RULES
    sec = re.search(r'!ROUTINGRULES(.*?)(?=!REPLACINGRULES|$)', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        for iface in range(6):
            rows = []
            for idx in range(10):
                mid  = re.search(rf'#IF{iface};RrMID{idx};(0x[0-9A-Fa-f]+)', text)
                msk  = re.search(rf'#IF{iface};RrMSK{idx};(0x[0-9A-Fa-f]+)', text)
                rtr  = re.search(rf'#IF{iface};RrRTR{idx};(0x[0-9A-Fa-f]+)', text)
                eid  = re.search(rf'#IF{iface};RrEID{idx};(0x[0-9A-Fa-f]+)', text)
                rls  = re.search(rf'#IF{iface};RrRLS{idx};(0x[0-9A-Fa-f]+)', text)
                ifs  = re.search(rf'#IF{iface};RrIFS{idx};([0-9,]+)', text)
                if mid and msk and rtr and eid and rls and ifs:
                    rv, iv = rls.group(1), ifs.group(1)
                    enabled = rv != '0x0' or any(v != '0' for v in iv.split(','))
                    rows.append({"index": idx, "mid": mid.group(1), "msk": msk.group(1),
                                 "rtr": rtr.group(1), "eid": eid.group(1),
                                 "rls": rv, "ifs": iv, "enabled": enabled})
            config["routing_rules"][iface] = rows

    # REPLACING RULES
    sec = re.search(r'!REPLACINGRULES(.*?)(?=!CANINTERFACES|$)', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        for iface in range(6):
            rows = []
            for idx in range(10):
                idb = re.search(rf'#IF{iface};DrIDB{idx};(0x[0-9A-Fa-f]+)', text)
                msk = re.search(rf'#IF{iface};DrMSK{idx};(0x[0-9A-Fa-f]+)', text)
                flg = re.search(rf'#IF{iface};DrFLG{idx};(0x[0-9A-Fa-f]+)', text)
                if idb and msk and flg:
                    iv, mv, fv = idb.group(1), msk.group(1), flg.group(1)
                    enabled = not (iv == '0x0' and mv == '0x0' and fv == '0x0')
                    rows.append({"index": idx, "idb": iv, "msk": mv, "flg": fv, "enabled": enabled})
            config["replacing_rules"][iface] = rows

    # CAN INTERFACES
    # Format: #CAN0;ABR;1;DEFBR;500;TRES;0;#CAN1;ABR;0;... (semicolon-separated, no newlines)
    sec = re.search(r'!CANINTERFACES(.*?)(?=!ETHERNET|$)', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        for i in range(6):
            # Extract the block for each CAN interface
            next_i = i + 1
            block_pat = rf'#CAN{i};(.*?)(?=#CAN{next_i};|!ETHERNET|$)'
            block_m = re.search(block_pat, text, re.DOTALL)
            if block_m:
                block = block_m.group(1)
                def _val(param, blk=block):
                    m = re.search(rf'{param};(\d+)', blk)
                    return m.group(1) if m else None
                abr_v = _val('ABR')
                if abr_v is not None:
                    config["can_interfaces"][i] = {
                        "abr":    abr_v,
                        "defbr":  _val('DEFBR') or "500",
                        "tres":   _val('TRES') or "0",
                        "fthr":   _val('FTHR') or "N/A",
                        "frstd":  _val('FRSTD') or "N/A",
                        "frsten": _val('FRSTEN') or "N/A",
                    }

    # ETHERNET
    sec = re.search(r'!ETHERNET(.*?)(?=!FUSENOTIFICATIONS|$)', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        ip    = re.search(r'IPADDR;([\d.]+)', text)
        nmask = re.search(r'NMASK;([\d.]+)', text)
        config["ethernet"] = {
            "ip":    ip.group(1) if ip else "N/A",
            "nmask": nmask.group(1) if nmask else "N/A",
        }

    # FUSE NOTIFICATIONS
    sec = re.search(r'!FUSENOTIFICATIONS(.*?)$', content, re.DOTALL)
    if sec:
        text = sec.group(1)
        for i in range(6):
            ntfe   = re.search(rf'#FUSE{i};NTFE;(\d+)', text)
            ntfid  = re.search(rf'#FUSE{i};NTFID;(0x[0-9A-Fa-f]+)', text)
            ntfstd = re.search(rf'#FUSE{i};NTFSTDID;(\d+)', text)
            ntfdl  = re.search(rf'#FUSE{i};NTFDLEN;(\d+)', text)
            ntfifs = re.search(rf'#FUSE{i};NTFIFS;([0-9,]+)', text)
            ntfdbs = re.search(rf'#FUSE{i};NTFDBS;([0-9A-Fa-fx,]+)', text)
            if ntfe:
                config["fuse_notifications"][i] = {
                    "enabled": ntfe.group(1),
                    "ntfid":   ntfid.group(1) if ntfid else "0x0",
                    "stdid":   ntfstd.group(1) if ntfstd else "0",
                    "dlen":    ntfdl.group(1) if ntfdl else "0",
                    "ifs":     ntfifs.group(1) if ntfifs else "0,0,0,0,0,0",
                    "dbs":     ntfdbs.group(1) if ntfdbs else "N/A",
                }
    return config


# ─────────────────────────────────────────────
# GENERADOR DE PDF
# ─────────────────────────────────────────────

def generate_pdf(config: dict, filename: str, report_date: str, serial: str = 'N/A') -> bytes:
    import base64, io as _io
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import (
        SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
        HRFlowable, PageBreak, Image as RLImage,
    )
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_LEFT, TA_CENTER

    # ── Paleta GSS ────────────────────────────
    DARK_GRN  = colors.HexColor('#002020')
    PETROL    = colors.HexColor('#143C50')
    PETROL2   = colors.HexColor('#0F3C5A')
    OFFWHITE  = colors.HexColor('#F4F8FA')
    BORDER    = colors.HexColor('#C8D8E0')
    GRAY_TXT  = colors.HexColor('#5A7A8A')
    DARK_TXT  = colors.HexColor('#002020')
    MID_TXT   = colors.HexColor('#1A2E38')
    ACCENT    = colors.HexColor('#86A2B4')
    CODE_FONT = 'Courier'

    buffer = _io.BytesIO()

    # ── Logo para PDF ─────────────────────────
    logo_bytes = base64.b64decode(GSS_LOGO_B64)
    logo_buf = _io.BytesIO(logo_bytes)

    def add_header_footer(canvas_obj, doc):
        canvas_obj.saveState()
        w, h = A4

        # Header bar
        canvas_obj.setFillColor(DARK_GRN)
        canvas_obj.rect(0, h - 26*mm, w, 26*mm, fill=1, stroke=0)

        # Franja acento
        canvas_obj.setFillColor(PETROL)
        canvas_obj.rect(0, h - 28*mm, w, 2*mm, fill=1, stroke=0)

        # Logo en header
        try:
            logo_buf.seek(0)
            canvas_obj.drawImage(
                RLImage(logo_buf),
                18*mm, h - 23*mm,
                width=38*mm, height=12*mm,
                preserveAspectRatio=True, mask='auto'
            )
        except Exception:
            canvas_obj.setFont('Helvetica-Bold', 10)
            canvas_obj.setFillColor(colors.white)
            canvas_obj.drawString(18*mm, h - 15*mm, 'GSS')

        # Título en header
        canvas_obj.setFont('Helvetica-Bold', 10)
        canvas_obj.setFillColor(colors.white)
        canvas_obj.drawString(64*mm, h - 11*mm, 'GATEWAY CONFIGURATION REPORT')
        canvas_obj.setFont('Helvetica', 7.5)
        canvas_obj.setFillColor(ACCENT)
        canvas_obj.drawString(64*mm, h - 17*mm, 'CAN / Ethernet Gateway  |  Global Supplies Solutions')

        # Fecha y página
        canvas_obj.setFont('Helvetica', 8)
        canvas_obj.setFillColor(colors.white)
        canvas_obj.drawRightString(w - 18*mm, h - 11*mm, report_date)
        canvas_obj.drawRightString(w - 18*mm, h - 17*mm, f'Page {doc.page}')

        # Footer bar
        canvas_obj.setFillColor(DARK_GRN)
        canvas_obj.rect(0, 0, w, 12*mm, fill=1, stroke=0)
        canvas_obj.setFillColor(ACCENT)
        canvas_obj.setFont('Helvetica', 7)
        canvas_obj.drawString(18*mm, 4.5*mm,
            'CONFIDENTIAL — Global Supplies Solutions. For authorized personnel only.')
        canvas_obj.setFillColor(colors.white)
        canvas_obj.setFont('Helvetica-Bold', 7)
        canvas_obj.drawRightString(w - 18*mm, 4.5*mm, 'Global Supplies Solutions')

        canvas_obj.restoreState()

    doc = SimpleDocTemplate(
        buffer, pagesize=A4,
        topMargin=34*mm, bottomMargin=20*mm,
        leftMargin=18*mm, rightMargin=18*mm,
    )

    # ── Estilos ───────────────────────────────
    S = lambda name, **kw: ParagraphStyle(name, **kw)
    sTitle   = S('T', fontSize=18, textColor=DARK_GRN, fontName='Helvetica-Bold',
                 spaceAfter=4, leading=22)
    sSub     = S('Sub', fontSize=9.5, textColor=GRAY_TXT, fontName='Helvetica',
                 spaceAfter=10, leading=14)
    sSecH    = S('SecH', fontSize=8.5, textColor=colors.white, fontName='Helvetica-Bold',
                 spaceAfter=0, leading=13, leftIndent=6)
    sSubH    = S('SubH', fontSize=8, textColor=PETROL2, fontName='Helvetica-Bold',
                 spaceAfter=0, leading=12)
    sBody    = S('Body', fontSize=8.5, textColor=MID_TXT, fontName='Helvetica',
                 spaceAfter=4, leading=13)
    sNote    = S('Note', fontSize=7.5, textColor=GRAY_TXT, fontName='Helvetica-Oblique',
                 spaceAfter=4, leading=11)
    sLabel   = S('Lbl', fontSize=7, textColor=GRAY_TXT, fontName='Helvetica-Bold',
                 spaceAfter=2, leading=10, letterSpacing=0.5)

    story = []

    # ── Helper: sección header ─────────────
    def sec_hdr(title):
        t = Table([[Paragraph(title, sSecH)]], colWidths=[174*mm])
        t.setStyle(TableStyle([
            ('BACKGROUND', (0,0), (-1,-1), DARK_GRN),
            ('TOPPADDING', (0,0), (-1,-1), 7),
            ('BOTTOMPADDING', (0,0), (-1,-1), 7),
            ('LEFTPADDING', (0,0), (-1,-1), 10),
        ]))
        story.append(Spacer(1, 5*mm))
        story.append(t)
        story.append(Spacer(1, 3*mm))

    def subsec_hdr(title):
        t = Table([[Paragraph(title, sSubH)]], colWidths=[174*mm])
        t.setStyle(TableStyle([
            ('BACKGROUND', (0,0), (-1,-1), colors.HexColor('#E4EEF4')),
            ('TOPPADDING', (0,0), (-1,-1), 5),
            ('BOTTOMPADDING', (0,0), (-1,-1), 5),
            ('LEFTPADDING', (0,0), (-1,-1), 10),
            ('LINEBELOW', (0,0), (-1,-1), 0.5, PETROL),
        ]))
        story.append(Spacer(1, 3*mm))
        story.append(t)
        story.append(Spacer(1, 2*mm))

    # ── Colores de tabla ───────────────────
    TH_STYLE = [
        ('BACKGROUND',    (0,0), (-1,0), PETROL),
        ('TEXTCOLOR',     (0,0), (-1,0), colors.white),
        ('FONTNAME',      (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE',      (0,0), (-1,0), 7),
        ('TOPPADDING',    (0,0), (-1,0), 8),
        ('BOTTOMPADDING', (0,0), (-1,0), 8),
        ('ROWBACKGROUNDS',(0,1), (-1,-1), [OFFWHITE, colors.white]),
        ('GRID',          (0,0), (-1,-1), 0.4, BORDER),
        ('FONTNAME',      (0,1), (-1,-1), CODE_FONT),
        ('FONTSIZE',      (0,1), (-1,-1), 8),
        ('TEXTCOLOR',     (0,1), (-1,-1), MID_TXT),
        ('PADDING',       (0,1), (-1,-1), 6),
        ('LEFTPADDING',   (0,0), (-1,-1), 8),
    ]

    def make_table(data, col_widths, extra_style=None):
        style = list(TH_STYLE)
        if extra_style:
            style.extend(extra_style)
        return Table(data, colWidths=col_widths, style=TableStyle(style))

    # ─────────── PORTADA ─────────────────────
    story.append(Spacer(1, 8*mm))
    story.append(Paragraph('GATEWAY CONFIGURATION REPORT', sLabel))
    story.append(Paragraph('Gateway Configuration Report', sTitle))
    story.append(Paragraph(
        'Global Supplies Solutions — Technical Configuration Document', sSub))
    story.append(HRFlowable(width='100%', thickness=2, color=PETROL, spaceAfter=10))

    # Resumen ejecutivo
    can_ifaces = config.get('can_interfaces', {})
    can0 = can_ifaces.get(0, {})
    active_filters = sum(
        1 for ifl in config['filters'].values() for f in ifl if f['enabled'])
    active_routes = sum(
        1 for irl in config['routing_rules'].values() for r in irl if r['enabled'])

    sum_data = [
        ['PARAMETER', 'VALUE', 'PARAMETER', 'VALUE'],
        ['Serial Number (S/N)', serial,
         'Equipment', 'CAN / Ethernet Gateway'],
        ['CAN0 Auto Baudrate',
         'Enabled' if can0.get('abr','0')=='1' else 'Disabled',
         'Active Filter Rules', str(active_filters)],
        ['Default Baudrate (All Channels)',
         f"{can0.get('defbr','500')} kbps",
         'Active Routing Rules', str(active_routes)],
        ['Bus Termination',
         'Enabled' if can0.get('tres','0')=='1' else 'Disabled',
         'Fast Reset (CAN1-5)',
         'Enabled' if can_ifaces.get(1,{}).get('frsten','0')=='1' else 'Disabled'],
    ]
    sum_col = [50*mm, 37*mm, 50*mm, 37*mm]
    story.append(make_table(sum_data, sum_col, [
        ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
        ('FONTNAME', (2,1),(2,-1), 'Helvetica-Bold'),
    ]))
    story.append(Spacer(1, 5*mm))
    story.append(Paragraph(
        'This report certifies the configuration parameters programmed into the Gateway gateway ' +
        'at the time of commissioning. CAN baudrate on every channel must match the network baudrate ' +
        'speed. This parameter must be verified on field prior to system operation.',
        sNote))

    # ─────────── 1. CAN INTERFACES ────────────
    story.append(PageBreak())
    sec_hdr('1.   CAN INTERFACE CONFIGURATION')
    story.append(Paragraph(
        'The CAN baudrate configured on each channel must match the baudrate of the connected CAN bus network. ' +
        'This parameter must be verified on field before placing the gateway into service. ' +
        'Six independent CAN interfaces are available (CAN0 through CAN5).',
        sBody))
    story.append(Spacer(1, 3*mm))

    can_headers = ['Interface', 'Auto BR', 'Baudrate (kbps)',
                   'Termination', 'FR Threshold', 'FR Std Dev (ms)', 'Fast Reset']
    can_rows = [can_headers]
    for i in range(6):
        c = can_ifaces.get(i, {})
        can_rows.append([
            f'CAN{i}',
            'AUTO' if c.get('abr','0')=='1' else 'MANUAL',
            f"{c.get('defbr','500')} kbps",
            'ON' if c.get('tres','0')=='1' else 'OFF',
            c.get('fthr','—') if c.get('fthr') not in [None,'N/A'] else '—',
            c.get('frstd','—') if c.get('frstd') not in [None,'N/A'] else '—',
            'ON' if c.get('frsten','0')=='1' else 'OFF',
        ])
    can_col = [22*mm, 20*mm, 32*mm, 26*mm, 26*mm, 26*mm, 22*mm]
    story.append(make_table(can_rows, can_col, [
        ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
        ('ALIGN', (0,0),(-1,-1), 'CENTER'),
        ('ALIGN', (0,1),(0,-1), 'LEFT'),
    ]))

    # ─────────── 2. CAN MESSAGE FILTERS ──────────
    sec_hdr('2.   CAN MESSAGE FILTERS')
    story.append(Paragraph(
        'Each CAN interface supports up to 10 configurable message filters. ' +
        'A filter is active when its ID base, mask, or flags are non-zero.',
        sBody))

    for iface, iface_filters in config['filters'].items():
        active = [f for f in iface_filters if f['enabled']]
        if not active:
            continue
        subsec_hdr(f'Interface IF{iface}')
        flt_h = ['Rule', 'ID Base (IDB)', 'Mask (MSK)', 'Flags (FLG)', 'Status']
        flt_rows = [flt_h]
        for f in iface_filters:
            flt_rows.append([
                f"Fl{f['index']}",
                f['idb'], f['msk'], f['flg'],
                'ACTIVE' if f['enabled'] else 'DISABLED',
            ])
        flt_col = [20*mm, 38*mm, 38*mm, 38*mm, 40*mm]
        story.append(make_table(flt_rows, flt_col, [
            ('ALIGN', (0,0),(-1,-1), 'CENTER'),
            ('ALIGN', (0,1),(0,-1), 'LEFT'),
            ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
        ]))
        story.append(Spacer(1, 2*mm))

    # ─────────── 3. ROUTING RULES ────────────
    sec_hdr('3.   MESSAGE ROUTING RULES')
    story.append(Paragraph(
        'Routing rules define how received CAN messages are forwarded between interfaces. ' +
        'Only rules with a non-zero RLS flag or non-zero destination interfaces are listed.',
        sBody))

    for iface, iface_rules in config['routing_rules'].items():
        active = [r for r in iface_rules if r['enabled']]
        if not active:
            continue
        subsec_hdr(f'Interface IF{iface}')
        rr_h = ['Rule', 'Msg ID', 'Mask', 'RTR', 'Ext. ID', 'RLS Flags', 'Dest. Interfaces']
        rr_rows = [rr_h]
        for r in active:
            rr_rows.append([
                f"Rr{r['index']}",
                r['mid'], r['msk'], r['rtr'],
                r['eid'], r['rls'], r['ifs'],
            ])
        rr_col = [14*mm, 22*mm, 22*mm, 14*mm, 18*mm, 22*mm, 62*mm]
        story.append(make_table(rr_rows, rr_col, [
            ('ALIGN', (0,0),(-1,-1), 'CENTER'),
            ('ALIGN', (0,1),(0,-1), 'LEFT'),
            ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
        ]))
        story.append(Spacer(1, 2*mm))

    # ─────────── 4. FUSE NOTIFICATIONS ────────
    sec_hdr('4.   FUSE NOTIFICATIONS')
    any_fuse = any(v.get('enabled','0')=='1' for v in config['fuse_notifications'].values())
    if not any_fuse:
        notice_t = Table([[Paragraph(
            'All fuse notification channels (FUSE0–FUSE5) are disabled. ' +
            'No CAN notifications will be generated upon fuse events.',
            S('NP', fontSize=8.5, textColor=GRAY_TXT,
              fontName='Helvetica-Oblique', spaceAfter=0, leading=13)
        )]], colWidths=[174*mm])
        notice_t.setStyle(TableStyle([
            ('BACKGROUND', (0,0),(-1,-1), colors.HexColor('#F0F6FA')),
            ('PADDING', (0,0),(-1,-1), 12),
            ('BOX', (0,0),(-1,-1), 0.5, BORDER),
        ]))
        story.append(notice_t)
    else:
        story.append(Paragraph('Active fuse notification channels:', sBody))

    fn_h = ['Channel', 'Status', 'Notif. ID', 'Std Frame ID', 'Data Len', 'Interfaces']
    fn_rows = [fn_h]
    for i, fuse in config['fuse_notifications'].items():
        fn_rows.append([
            f'FUSE{i}',
            'ACTIVE' if fuse.get('enabled')=='1' else 'DISABLED',
            fuse.get('ntfid','0x0'), fuse.get('stdid','0'),
            fuse.get('dlen','0'), fuse.get('ifs','N/A'),
        ])
    fn_col = [22*mm, 22*mm, 28*mm, 28*mm, 22*mm, 52*mm]
    story.append(Spacer(1, 3*mm))
    story.append(make_table(fn_rows, fn_col, [
        ('ALIGN', (0,0),(-1,-1), 'CENTER'),
        ('ALIGN', (0,1),(0,-1), 'LEFT'),
        ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
    ]))

    # ─────────── DOCUMENT INFORMATION ────────
    story.append(PageBreak())
    sec_hdr('DOCUMENT INFORMATION')
    story.append(Spacer(1, 5*mm))
    doc_data = [
        ['Field', 'Value'],
        ['Report Date',         report_date],
        ['Serial Number (S/N)', serial],
        ['Equipment',          'CAN / Ethernet Gateway'],
        ['Total CAN Interfaces','6  (CAN0 – CAN5)'],
        ['Total Filter Slots',  '60  (10 per interface)'],
        ['Total Routing Slots', '60  (10 per interface)'],
        ['Gateway Status',      'Fully Configured and Commissioned'],
    ]
    doc_col = [65*mm, 109*mm]
    story.append(make_table(doc_data, doc_col, [
        ('FONTNAME', (0,1),(0,-1), 'Helvetica-Bold'),
        ('BACKGROUND', (0,0),(-1,0), DARK_GRN),
        ('BACKGROUND', (0,-1),(-1,-1), colors.HexColor('#D1FAE5')),
        ('TEXTCOLOR', (0,-1),(-1,-1), colors.HexColor('#065F46')),
        ('FONTNAME', (0,-1),(-1,-1), 'Helvetica-Bold'),
    ]))
    story.append(Spacer(1, 8*mm))
    story.append(HRFlowable(width='100%', thickness=1, color=BORDER, spaceAfter=8))
    story.append(Paragraph(
        'The information contained herein reflects the exact parameters stored in the gateway ' +
        'at the time of configuration. Any subsequent changes to the device will require ' +
        'a new configuration report.',
        sNote))

    doc.build(story, onFirstPage=add_header_footer, onLaterPages=add_header_footer)
    return buffer.getvalue()


# ─────────────────────────────────────────────
# COMPONENTES DE VISUALIZACIÓN
# ─────────────────────────────────────────────

def badge(text, tipo="active"):
    return f'<span class="badge-{tipo}">{text}</span>'

def render_header():
    logo_src = f"data:image/png;base64,{GSS_LOGO_B64}"
    st.markdown(f"""
    <div class="report-header">
        <img class="header-logo" src="{logo_src}" alt="Global Supplies Solutions">
        <div class="header-divider"></div>
        <div class="header-text">
            <div class="header-badge">Gateway Configuration Report</div>
            <h1>Global Supplies Solutions</h1>
            <p>CAN / Ethernet Gateway &nbsp;&mdash;&nbsp; Configuration Analysis &amp; Export Tool</p>
        </div>
    </div>
    """, unsafe_allow_html=True)

def render_summary_cards(config, serial="N/A"):
    can_ifaces = config.get('can_interfaces', {})
    can0 = can_ifaces.get(0, {})
    can1 = can_ifaces.get(1, {})
    active_filters = sum(
        1 for ifl in config['filters'].values() for f in ifl if f['enabled'])
    active_routes = sum(
        1 for irl in config['routing_rules'].values() for r in irl if r['enabled'])
    any_fuse = any(v.get('enabled','0')=='1' for v in config['fuse_notifications'].values())

    # Serial number highlight
    st.markdown(f"""
    <div style="background:linear-gradient(90deg,#002020,#184060);
                border-radius:8px;padding:0.9rem 1.4rem;margin-bottom:1rem;
                display:flex;align-items:center;gap:1.5rem;">
        <div>
            <div style="font-size:0.65rem;font-weight:700;color:#86A2B4;
                        text-transform:uppercase;letter-spacing:1.5px;">Device Serial Number</div>
            <div style="font-size:1.4rem;font-weight:700;color:white;
                        font-family:'Courier New',monospace;letter-spacing:2px;">S/N &nbsp;{serial}</div>
        </div>
        <div style="width:1px;height:40px;background:rgba(255,255,255,0.2);"></div>
        <div>
            <div style="font-size:0.65rem;font-weight:700;color:#86A2B4;
                        text-transform:uppercase;letter-spacing:1.5px;">Equipment</div>
            <div style="font-size:0.95rem;font-weight:600;color:#C8DCF0;">
                CAN / Ethernet Gateway</div>
        </div>
        <div style="width:1px;height:40px;background:rgba(255,255,255,0.2);"></div>
        <div>
            <div style="font-size:0.65rem;font-weight:700;color:#86A2B4;
                        text-transform:uppercase;letter-spacing:1.5px;">Status</div>
            <div style="font-size:0.95rem;font-weight:600;color:#6EE7B7;">
                Fully Configured</div>
        </div>
    </div>
    """, unsafe_allow_html=True)

    c1,c2,c3,c4 = st.columns(4)
    with c1: st.metric("Default Baudrate", f"{can0.get('defbr','500')} kbps")
    with c2: st.metric("CAN0 Auto Baudrate", "Yes" if can0.get('abr','0')=='1' else "No")
    with c3: st.metric("Active Filters", str(active_filters))
    with c4: st.metric("Active Routes", str(active_routes))

    c5,c6,c7,c8 = st.columns(4)
    with c5: st.metric("Fast Reset CAN1-5", "Yes" if can1.get('frsten','0')=='1' else "No")
    with c6: st.metric("FR Threshold", f"{can1.get('fthr','—')} err" if can1.get('fthr') not in [None,'N/A'] else "—")
    with c7: st.metric("FR Std Dev", f"{can1.get('frstd','—')} ms" if can1.get('frstd') not in [None,'N/A'] else "—")
    with c8: st.metric("Fuse Notifications", "Active" if any_fuse else "None")

def render_can_interfaces(can_ifaces):
    rows = ""
    for i in range(6):
        c = can_ifaces.get(i, {})
        abr_b  = badge("AUTO","auto") if c.get('abr','0')=='1' else badge("MANUAL","manual")
        tres_b = badge("ON","active") if c.get('tres','0')=='1' else badge("OFF","inactive")
        fr_b   = badge("ON","active") if c.get('frsten','0')=='1' else badge("OFF","inactive")
        fthr   = c.get('fthr','—'); fthr = '—' if fthr == 'N/A' else fthr
        frstd  = c.get('frstd','—'); frstd = '—' if frstd == 'N/A' else frstd
        rows += f"""<tr>
            <td class="label-col">CAN{i}</td>
            <td>{abr_b}</td>
            <td><strong>{c.get('defbr','500')} kbps</strong></td>
            <td>{tres_b}</td>
            <td>{fthr}</td>
            <td>{frstd}</td>
            <td>{fr_b}</td>
        </tr>"""
    html = f"""
    <table class="custom-table">
        <thead><tr>
            <th>Interface</th><th>Auto Baudrate</th><th>Baudrate</th>
            <th>Termination</th><th>FR Threshold</th><th>FR Std Dev (ms)</th><th>Fast Reset</th>
        </tr></thead>
        <tbody>{rows}</tbody>
    </table>"""
    st.markdown(f'<div class="section-card"><div class="section-title">CAN Interface Configuration</div>{html}</div>',
                unsafe_allow_html=True)

def render_filters_tab(filters):
    tabs = st.tabs([f"IF{i}" for i in range(6)])
    for i, tab in enumerate(tabs):
        with tab:
            active = [f for f in filters.get(i, []) if f['enabled']]
            if not active:
                st.markdown('<p class="notice-box">No active filters on this interface. All messages are accepted.</p>',
                            unsafe_allow_html=True)
            else:
                rows = "".join(
                    f'<tr><td class="label-col">Fl{f["index"]}</td>' +
                    f'<td>{f["idb"]}</td><td>{f["msk"]}</td><td>{f["flg"]}</td>' +
                    f'<td>{badge("ACTIVE","active") if f["enabled"] else badge("DISABLED","inactive")}</td></tr>'
                    for f in filters.get(i, []) if f['enabled']
                )
                st.markdown(f"""
                <table class="custom-table">
                    <thead><tr><th>Rule</th><th>ID Base (IDB)</th><th>Mask (MSK)</th>
                    <th>Flags (FLG)</th><th>Status</th></tr></thead>
                    <tbody>{rows}</tbody>
                </table>""", unsafe_allow_html=True)

def render_routing_tab(routing_rules):
    tabs = st.tabs([f"IF{i}" for i in range(6)])
    for i, tab in enumerate(tabs):
        with tab:
            active = [r for r in routing_rules.get(i, []) if r['enabled']]
            if not active:
                st.markdown('<p class="notice-box">No routing rules configured on this interface.</p>',
                            unsafe_allow_html=True)
            else:
                rows = "".join(
                    f'<tr><td class="label-col">Rr{r["index"]}</td>' +
                    f'<td>{r["mid"]}</td><td>{r["msk"]}</td><td>{r["rtr"]}</td>' +
                    f'<td>{r["eid"]}</td><td>{r["rls"]}</td><td>{r["ifs"]}</td></tr>'
                    for r in active
                )
                st.markdown(f"""
                <table class="custom-table">
                    <thead><tr><th>Rule</th><th>Msg ID</th><th>Mask</th><th>RTR</th>
                    <th>Ext. ID</th><th>RLS Flags</th><th>Dest. Interfaces</th></tr></thead>
                    <tbody>{rows}</tbody>
                </table>""", unsafe_allow_html=True)

def render_fuse_notifications(fuse_notifications):
    rows = "".join(
        f'<tr><td class="label-col">FUSE{i}</td>' +
        f'<td>{badge("ACTIVE","active") if fuse.get("enabled")=="1" else badge("DISABLED","inactive")}</td>' +
        f'<td>{fuse.get("ntfid","0x0")}</td><td>{fuse.get("stdid","0")}</td>' +
        f'<td>{fuse.get("dlen","0")}</td><td>{fuse.get("ifs","N/A")}</td></tr>'
        for i, fuse in fuse_notifications.items()
    )
    html = f"""
    <table class="custom-table">
        <thead><tr><th>Channel</th><th>Status</th><th>Notification ID</th>
        <th>Std Frame ID</th><th>Data Length</th><th>Interfaces</th></tr></thead>
        <tbody>{rows}</tbody>
    </table>"""
    st.markdown(f'<div class="section-card"><div class="section-title">Fuse Notifications</div>{html}</div>',
                unsafe_allow_html=True)


# ─────────────────────────────────────────────
# APP PRINCIPAL
# ─────────────────────────────────────────────

def main():
    render_header()

    if 'config' not in st.session_state: st.session_state.config = None
    if 'filename' not in st.session_state: st.session_state.filename = ""
    if 'raw_content' not in st.session_state: st.session_state.raw_content = ""

    # ── PASO 1 ────────────────────────────────
    st.markdown('<div class="step-label">Step 1 &mdash; Load Configuration File</div>',
                unsafe_allow_html=True)
    st.markdown('<div class="step-desc">Upload the .txt configuration file exported from the Gateway gateway. The file will be parsed automatically upon upload.</div>',
                unsafe_allow_html=True)

    uploaded = st.file_uploader(
        label="Drop configuration file",
        type=["txt"], label_visibility="collapsed")

    if uploaded is not None:
        content = uploaded.read().decode('utf-8', errors='replace')
        st.session_state.raw_content = content
        st.session_state.config = parse_config(content)
        st.session_state.filename = uploaded.name
        st.success(f"File loaded successfully: {uploaded.name}")

    if st.session_state.config is not None:
        cfg = st.session_state.config
        fname = st.session_state.filename

        st.markdown('<div class="divider"></div>', unsafe_allow_html=True)

        # ── PASO 2 ────────────────────────────
        serial = extract_serial(fname)
        st.markdown('<div class="step-label">Step 2 &mdash; Configuration Overview</div>',
                    unsafe_allow_html=True)
        st.markdown('<div class="step-desc">Review all parameters parsed from the device configuration file.</div>',
                    unsafe_allow_html=True)
        st.markdown("<br>", unsafe_allow_html=True)
        render_summary_cards(cfg, serial)
        st.markdown("<br>", unsafe_allow_html=True)

        tab_can, tab_flt, tab_rrt, tab_fuse, tab_raw = st.tabs([
            "CAN Interfaces", "Filters", "Routing Rules",
            "Fuse Notifications", "Raw File",
        ])

        with tab_can:
            render_can_interfaces(cfg.get('can_interfaces', {}))

        with tab_flt:
            st.markdown('<div class="section-card"><div class="section-title">CAN Message Filters</div>',
                        unsafe_allow_html=True)
            render_filters_tab(cfg.get('filters', {}))
            st.markdown('</div>', unsafe_allow_html=True)

        with tab_rrt:
            st.markdown('<div class="section-card"><div class="section-title">Message Routing Rules</div>',
                        unsafe_allow_html=True)
            render_routing_tab(cfg.get('routing_rules', {}))
            st.markdown('</div>', unsafe_allow_html=True)

        with tab_fuse:
            render_fuse_notifications(cfg.get('fuse_notifications', {}))

        with tab_raw:
            st.markdown('<div class="section-card"><div class="section-title">Raw Configuration File</div>',
                        unsafe_allow_html=True)
            st.code(st.session_state.raw_content, language="text")
            st.markdown('</div>', unsafe_allow_html=True)

        # ── PASO 3 ────────────────────────────
        st.markdown('<div class="divider"></div>', unsafe_allow_html=True)
        st.markdown('<div class="step-label">Step 3 &mdash; Export PDF Report</div>',
                    unsafe_allow_html=True)

        col_info, col_btn = st.columns([3, 1])
        with col_info:
            st.markdown(
                '<p class="step-desc">The PDF report will include all configuration sections ' +
                'formatted as a professional technical deliverable, ready for customer submission.</p>',
                unsafe_allow_html=True)
        with col_btn:
            report_date = datetime.now().strftime("%Y-%m-%d")
            pdf_bytes = generate_pdf(cfg, fname, report_date, serial)
            pdf_name = fname.replace('.txt', '_report.pdf') if fname.endswith('.txt') else 'gateway_report.pdf'
            st.download_button(
                label="Export PDF Report",
                data=pdf_bytes,
                file_name=pdf_name,
                mime="application/pdf",
            )
    else:
        st.markdown("""
        <div style="text-align:center;padding:4rem 2rem;color:#8AAAB8;
                    background:white;border-radius:10px;border:1px solid #D0DDE4;margin-top:1rem;">
            <div style="font-size:1rem;font-weight:600;color:#5A7A8A;margin-bottom:0.4rem;">
                No file loaded
            </div>
            <div style="font-size:0.85rem;">
                Upload a gateway configuration .txt file above to begin.
            </div>
        </div>
        """, unsafe_allow_html=True)

    st.markdown("""
    <div class="report-footer">
        Global Supplies Solutions &nbsp;&mdash;&nbsp; Gateway Configuration Report
        &nbsp;|&nbsp; CAN / Ethernet Gateway &nbsp;|&nbsp; Confidential
    </div>
    """, unsafe_allow_html=True)


if __name__ == "__main__":
    main()
